SELECT pi.*, u.nickname AS student_name
FROM project_info pi
LEFT JOIN user u ON pi.sid = u.id


        AND pi.id = #{query.id}


        AND pi.sid = #{query.sid}


        AND pi.tid= #{query.tid}


        AND pi.status = #{query.status}


        AND pi.title LIKE CONCAT('%', #{query.title}, '%')


        AND pi.description LIKE CONCAT('%', #{query.description}, '%')


        AND pi.opinion LIKE CONCAT('%', #{query.opinion}, '%')




        AND pi.create_time >= #{query.createTimeStart}


        AND pi.create_time <= #{query.createTimeEnd}




        AND pi.update_time >= #{query.updateTimeStart}


        AND pi.update_time <= #{query.updateTimeEnd}





        ORDER BY ${query.orderByClause}


        ORDER BY pi.id
        ASC
        DESC
